async function n(t){const o=await fetch(`/api/download-pdf?rid=${encodeURIComponent(t)}`);if(!o.ok)throw new Error(`Failed to download PDF (HTTP ${o.status})`);return await o.arrayBuffer()}async function d(t,o="signed_document.pdf"){const a=await fetch(`/api/upload-pdf?filename=${encodeURIComponent(o)}`,{method:"POST",headers:{"Content-Type":"application/octet-stream"},body:new Blob([t],{type:"application/pdf"})});if(!a.ok)throw new Error(`Failed to upload PDF (HTTP ${a.status})`);return(await a.json()).rid}export{n as downloadPdf,d as uploadSignedPdf};
